import{_ as o,o as t,c as a,a2 as n}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"RFC 0024 — Plugin compatibility & versioning","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0024-plugin-compatibility.md","filePath":"rfcs/0024-plugin-compatibility.md"}'),r={name:"rfcs/0024-plugin-compatibility.md"};function i(s,e,d,l,c,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="rfc-0024-—-plugin-compatibility-versioning" tabindex="-1">RFC 0024 — Plugin compatibility &amp; versioning <a class="header-anchor" href="#rfc-0024-—-plugin-compatibility-versioning" aria-label="Permalink to &quot;RFC 0024 — Plugin compatibility &amp; versioning&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>packages/manifest</code> (<code>maxPlatformVersion</code> + semver validation + <code>CURRENT_MANIFEST_SCHEMA_VERSION</code> + a <code>checkCompatibility</code> resolver; add <code>semver</code>), <code>scripts/generate-registry.ts</code> + <code>scripts/install-plugins.ts</code> + <code>bin/sv</code> (install/build gates), runtime startup + <code>plugin_status</code> + <code>/api/admin/health</code> (boot disable + surface), <code>registry/plugins.json</code> (Task 0.5.19), <code>docs/plugin-development.md</code> + <code>docs/self-hosting.md</code>; <strong>amends RFC 0006</strong> (consumes the boot gate + admin-health surfacing), disambiguates from <strong>RFC 0007</strong> (<code>schemaVersion</code> clash), relates to Task 0.5.19/0.5.20<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.5.22; documentation-first. This RFC defines the compatibility model and where it is enforced; SRS requirement IDs, scheduling, and task allocation are deferred.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Make the manifest&#39;s dormant version fields functional. Today <code>schemaVersion</code> and <code>compatibility.minPlatformVersion</code> are declared, structurally validated, and then <strong>ignored</strong> — no semver check, no comparison against the running platform, no <code>maxPlatformVersion</code>. This RFC:</p><ul><li>adds real <strong>semver</strong> validation and a <strong>platform-version compatibility</strong> model — <strong><code>minPlatformVersion</code> hard-enforced</strong>, a new <strong><code>maxPlatformVersion</code> advisory</strong> (warns, doesn&#39;t block);</li><li>makes <strong><code>schemaVersion</code></strong> functional via a current-version constant (accept older, reject unknown-newer manifest formats);</li><li>enforces all of it through <strong>one shared resolver</strong> at four points — <strong>install</strong>, <strong>build</strong>, <strong>boot</strong>, and the <strong>registry</strong> — with <strong>tiered</strong> behaviour: install and build <strong>refuse</strong> an incompatible plugin; boot <strong>disables and surfaces</strong> it so a single bad plugin never bricks the instance.</li></ul><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>A plugin built for a newer platform should fail loudly at install rather than misbehave; an instance that upgrades its platform shouldn&#39;t be bricked by one plugin that now requires something newer; and the manifest format needs room to evolve without breaking every existing plugin. The fields to express all this already exist — they&#39;re just inert. RFC 0006 already called for reusing <code>minPlatformVersion</code> as an install-/start-time check &quot;so a plugin built for a newer platform fails loudly,&quot; and deferred the implementation; this RFC supplies the model.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Declared, not enforced.</strong> <code>packages/manifest/src/schema.ts</code> has <code>schemaVersion: z.number().int().positive()</code> (always <code>1</code>, no constant) and <code>compatibility: { minPlatformVersion: z.string().min(1) }</code> (any non-empty string). A repo-wide search finds <strong>no version comparison anywhere</strong> — both fields are declarative.</li><li><strong>No <code>maxPlatformVersion</code></strong> and <strong>no <code>semver</code> library</strong> in the repo.</li><li><strong>Validation pipeline.</strong> <code>validateManifest</code> (<code>packages/manifest/src/validate.ts</code>) is structural-only; <code>scripts/generate-registry.ts</code> fails the build on an invalid manifest — the natural place to add a compatibility gate.</li><li><strong>Platform version.</strong> Lives in root <code>package.json</code> (currently <code>0.6.0</code>), read via <code>getPlatformVersion()</code> (<code>packages/sdk/src/platform.ts</code>), exposed through <code>sdk.platform.getConfig().version</code> and <code>/api/admin/health</code>.</li><li><strong>RFC 0006 anticipated this</strong> — &quot;reuse <code>compatibility.minPlatformVersion</code> as an install-/start-time check … fail loudly,&quot; plus a startup version gate surfaced in admin health (deferred). <strong>Task 0.5.19</strong> registry &quot;must target compatible platform version&quot; is a human review note today; <strong>Task 0.5.20</strong> defines SDK semver.</li></ul><h2 id="the-three-version-concepts-disambiguation" tabindex="-1">The three version concepts (disambiguation) <a class="header-anchor" href="#the-three-version-concepts-disambiguation" aria-label="Permalink to &quot;The three version concepts (disambiguation)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Versions what</th><th>Compared against</th></tr></thead><tbody><tr><td>Manifest <strong><code>schemaVersion</code></strong></td><td>The <strong>manifest format</strong> itself</td><td>The platform&#39;s <code>CURRENT_MANIFEST_SCHEMA_VERSION</code></td></tr><tr><td><strong><code>compatibility.minPlatformVersion</code></strong> / <strong><code>maxPlatformVersion</code></strong></td><td>The <strong>platform version range</strong> the plugin supports</td><td>The running platform version (semver)</td></tr><tr><td><strong>SDK semver</strong> (Task 0.5.20)</td><td>The plugin↔platform <strong>contract</strong></td><td>(v1: implied by platform version)</td></tr></tbody></table><p>For v1 the <strong>platform version is the single compatibility axis</strong> a plugin declares — the SDK ships with the platform, so plugins don&#39;t separately pin an SDK range.</p><p><strong>Note the clash with RFC 0007:</strong> that RFC reuses the name <code>schemaVersion</code> for a plugin&#39;s <strong>data-format</strong> version inside export bundles — a different field in a different namespace. This RFC&#39;s <code>schemaVersion</code> is the <strong>manifest format</strong> version. The two are intentionally distinct.</p><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="semver-validation" tabindex="-1">Semver validation <a class="header-anchor" href="#semver-validation" aria-label="Permalink to &quot;Semver validation&quot;">​</a></h3><p>Add <code>semver</code> (pure JS, catalog-pinned) to <code>packages/manifest</code>. Tighten <code>minPlatformVersion</code> (and the new <code>maxPlatformVersion</code>) from <code>z.string().min(1)</code> to <strong>valid semver</strong> at validation time, and use real semver comparison (a lexicographic compare would mis-order <code>0.10.0</code> vs <code>0.9.0</code>).</p><h3 id="minplatformversion-hard-maxplatformversion-advisory" tabindex="-1"><code>minPlatformVersion</code> (hard) + <code>maxPlatformVersion</code> (advisory) <a class="header-anchor" href="#minplatformversion-hard-maxplatformversion-advisory" aria-label="Permalink to &quot;`minPlatformVersion` (hard) + `maxPlatformVersion` (advisory)&quot;">​</a></h3><ul><li><strong><code>minPlatformVersion</code></strong> — a <strong>hard gate</strong>: a plugin whose minimum exceeds the running platform version is <strong>incompatible</strong>.</li><li><strong><code>maxPlatformVersion</code></strong> — a new <strong>optional</strong> field, <strong>advisory</strong>: a plugin running on a platform <em>above</em> its declared max still loads, but emits a <strong>warning</strong> (surfaced in Console/health, logged) — &quot;tested up to X; running on Y.&quot; This avoids stranding working plugins or forcing a max bump every platform release.</li></ul><h3 id="schemaversion-functional" tabindex="-1"><code>schemaVersion</code> (functional) <a class="header-anchor" href="#schemaversion-functional" aria-label="Permalink to &quot;`schemaVersion` (functional)&quot;">​</a></h3><p>Add <code>CURRENT_MANIFEST_SCHEMA_VERSION</code> (= 1) in <code>packages/manifest</code>. Accept a manifest with <code>schemaVersion ≤ current</code> (older plugins keep working as the format evolves); <strong>reject</strong> a higher value with a clear error — &quot;manifest format newer than this platform understands.&quot; (An optional <code>MIN_SUPPORTED_SCHEMA_VERSION</code> lets ancient formats be dropped eventually.)</p><h3 id="the-shared-resolver" tabindex="-1">The shared resolver <a class="header-anchor" href="#the-shared-resolver" aria-label="Permalink to &quot;The shared resolver&quot;">​</a></h3><p>A pure function in <code>packages/manifest</code>, reused everywhere so behaviour is identical:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">checkCompatibility</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  manifest: SovereignManifest,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  platformVersion: string,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">): { compatible: boolean; reason</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> string; warnings: string[] };</span></span></code></pre></div><ul><li><code>compatible: false</code> + <code>reason</code> when <code>minPlatformVersion</code> &gt; platform, or <code>schemaVersion</code> &gt; current.</li><li><code>warnings</code> for the advisory <code>maxPlatformVersion</code> overshoot.</li><li>No platform dependencies; unit-tested in isolation.</li></ul><h3 id="tiered-enforcement" tabindex="-1">Tiered enforcement <a class="header-anchor" href="#tiered-enforcement" aria-label="Permalink to &quot;Tiered enforcement&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Check point</th><th>Behaviour on incompatible</th></tr></thead><tbody><tr><td><strong>Install</strong> (<code>sv plugin add</code> / <code>install-plugins</code>)</td><td><strong>Refuse</strong> with a clear error before adding.</td></tr><tr><td><strong>Build / generate</strong> (<code>generate-registry.ts</code>)</td><td><strong>Fail the build</strong> for composed in-repo plugins (the dev path).</td></tr><tr><td><strong>Boot / startup</strong></td><td><strong>Disable + surface</strong> the plugin (Console/health) — never brick.</td></tr><tr><td><strong>Registry</strong> (Task 0.5.19)</td><td><strong>Filter</strong> so users only see plugins installable on their version.</td></tr></tbody></table><p>The boot path re-checks against the (possibly upgraded) platform version and marks the plugin <strong>incompatible-disabled</strong> — distinct from an admin-disabled plugin in <code>plugin_status</code>/Console — feeding RFC 0006&#39;s admin-health version gate. Advisory-max warnings surface but don&#39;t disable.</p><h3 id="coordination-with-rfc-0006-0007" tabindex="-1">Coordination with RFC 0006 / 0007 <a class="header-anchor" href="#coordination-with-rfc-0006-0007" aria-label="Permalink to &quot;Coordination with RFC 0006 / 0007&quot;">​</a></h3><p>This RFC owns the <strong>model + fields + resolver + install/build checks</strong>; <strong>RFC 0006 consumes</strong> the boot-time gate and the admin-health surfacing (cross-referenced; a light amendment). RFC 0007&#39;s export-bundle <code>schemaVersion</code> remains a separate concept (noted above).</p><h2 id="ui-flows" tabindex="-1">UI / flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI / flows&quot;">​</a></h2><p>A developer whose <code>minPlatformVersion</code> is too new gets a build/install error naming <strong>required vs current</strong> version. After a platform upgrade, an incompatible installed plugin appears as <strong>disabled-incompatible</strong> in Console + <code>/api/admin/health</code> with the reason. A plugin past its advisory <code>max</code> shows a <strong>non-blocking warning</strong>. The registry hides plugins that don&#39;t satisfy the viewer&#39;s platform version.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Hand-rolled version compare.</strong> Rejected — lexicographic ordering mishandles <code>0.10.0</code> vs <code>0.9.0</code>; <code>semver</code> is tiny, pure-JS, and correct.</li><li><strong>Hard-enforced <code>maxPlatformVersion</code>.</strong> Rejected (per decision) — it strands working plugins and forces a maintenance bump on every platform release; advisory is the pragmatic default.</li><li><strong>Fail loudly everywhere on incompatibility.</strong> Rejected — at boot, one external plugin requiring a newer platform would take down the whole instance; tiered (refuse on the explicit actions, disable+surface at boot) is safer.</li><li><strong>Leave <code>schemaVersion</code> declarative.</strong> Rejected — the goal includes real schema validation + backward compatibility as the manifest format evolves.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Incompatible-disabled representation</strong> — a <code>plugin_status</code> flag vs derived at boot from the resolver.</li><li><strong>Max escalation</strong> — should advisory <code>max</code> ever become hard at a platform <strong>major</strong> boundary?</li><li><strong><code>MIN_SUPPORTED_SCHEMA_VERSION</code></strong> — introduce now or when the format first changes?</li><li><strong>SDK range</strong> — should plugins additionally pin an SDK version range later (deferred — platform version is the v1 axis)?</li><li><strong>Requirement IDs</strong> — deferred until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong></li><li><strong>When accepted &amp; scheduled:</strong> add <code>semver</code> + <code>maxPlatformVersion</code> + semver validation + <code>CURRENT_MANIFEST_SCHEMA_VERSION</code> + the <code>checkCompatibility</code> resolver (manifest <strong>minor</strong> bump); wire the four check points; surface boot incompatibility in Console/health (with RFC 0006); document in <code>docs/plugin-development.md</code> + <code>docs/self-hosting.md</code> (+ docs-parity for the new field).</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; makes <code>schemaVersion</code> + <code>compatibility</code> functional — semver-validated <code>minPlatformVersion</code> (hard) + advisory <code>maxPlatformVersion</code>, a <code>CURRENT_MANIFEST_SCHEMA_VERSION</code> accept-range, one shared resolver, tiered enforcement at install/build/boot/registry; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.5.22.</td></tr></tbody></table>',40)])])}const p=o(r,[["render",i]]);export{m as __pageData,p as default};
